{
  "citations": [
    {
      "span_start": 112,
      "span_end": 147,
      "span_text": "وَمَا نُنَزِّلُهُ إِلَّا بِقَدَرٍ مَعْلُومٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 183,
      "span_end": 356,
      "span_text": "إن أحَدَكُمْ يُجْمَعُ خَلْقُهُ في بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمَاً نُطْفَةً، ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذلكَ، ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذلكَ، ثُمَّ يُرْسَلُ المَلَكُ فَيَنْفُخُ فِيهِ الرُّوحَ، وَيُؤْمَرُ بأرْبَعِ كَلِماتٍ: بِكَتْب رِزْقِهِ وَأجَلِهِ وَعَمَلِهِ وَشَقِيٍّ أَوْ سَعِيدٍ",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 418,
      "span_end": 516,
      "span_text": "وَضَرَبَ الله مَثَلاً قَرْيَةً كَانَتْ آمِنَةً مُطْمَئِنَّةً يَأْتِيهَا رِزْقُهَا رَغَداً مِّطْمَئِنّا يَأْتِيهَا رِزْقُهَا رَغَدًا مِّطْمئنِّين",
      "citation_type": "Aya"
    },
    {
      "span_start": 569,
      "span_end": 645,
      "span_text": "أَيُّهَا النَّاسُ ، اتَّقُوا اللَّهَ وَأَجْمِلُوا فِي الطَّلَبِ ، فَإِنَّ نَفْسًا لَنْ تَمُوتَ حَتَّى تَسْتَوْفِي رِزْقَهَا وَإِنْ أَبْطَأَ عَنْهَا",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 800,
      "span_end": 848,
      "span_text": "وَمَا مِنْ دَابَّةٍ فِي الْأَرْضِ إِلاَّ عَلَى اللَّهِ رِزْقُهَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 870,
      "span_end": 944,
      "span_text": "وَكَأَيِّنْ مِنْ دَابَّةٍ لا تَحْمِلُ رِزْقَهَا اللَّهُ يَرْزُقُهَا وَإِيَّاكُمْ",
      "citation_type": "Aya"
    },
    {
      "span_start": 970,
      "span_end": 1030,
      "span_text": "مَا يَفْتَحِ اللَّهُ لِلنَّاسِ مِنْ رَحْمَةٍ فَلا مُمْسِكَ لَهَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 1050,
      "span_end": 1100,
      "span_text": "وَإِنْ يُرِدْكَ بِخَيْرٍ فَلا رَادَّ لِفَضْلِهِ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1160,
      "span_end": 1333,
      "span_text": "إنَّ أحَدَكُمْ يُجْمَعُ خَلْقُهُ في بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمَاً نُطْفَةً، ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذلكَ، ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذلكَ، ثُمَّ يُرْسَلُ المَلَكُ فَيَنْفُخُ فِيهِ الرُّوحَ، وَيُؤْمَرُ بأرْبَعِ كَلِماتٍ: بِكَتْب رِزْقِهِ وَأجَلِهِ وَعَمَلِهِ وَشَقِيٍّ أَوْ سَعِيدٍ",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 1370,
      "span_end": 1480,
      "span_text": "فِي يَوْمَيْنِ وَتَجْعَلُونَ لَهُ أَندَاداً ذَلِكَ رَبُّ العالمين وَجَعَلَ فِيهَا رَوَاسِيَ مِن فَوْقِهَا وَبَارَكَ فِيهَا وَقَدَّرَ فِيهَآ أَقْوَاتَهَا في أَرْبَعَةِ أَيَّامٍ سَوَآءً لِّلسَّآئِلِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1490,
      "span_end": 1526,
      "span_text": "وَمَا نُنَزِّلُهُ إِلاَّ بِقَدَرٍ مَّعْلُومٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1550,
      "span_end": 1670,
      "span_text": "وَضَرَبَ الله مَثَلاً قَرْيَةً كَانَتْ آمِنَةً مُّطْمَئِنَّةً يَأْتِيهَا رِزْقُهَا رَغَداً مِّن كُلِّ مَكَانٍ فَكَفَرَتْ بِأَنْعُمِ الله فَأَذَاقَهَا الله لِبَاسَ الجوع والخوف بِمَا كَانُواْ يَصْنَعُونَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1685,
      "span_end": 1785,
      "span_text": "إِنَّ الذين تَوَفَّاهُمُ الملائكة ظالمي أَنْفُسِهِمْ قَالُواْ فِيمَ كُنتُمْ قَالُواْ كُنَّا مُسْتَضْعَفِينَ فِي الأرض قالوا أَلَمْ تَكُنْ أَرْضُ الله وَاسِعَةً فَتُهَاجِرُواْ فِيهَا",
      "citation_type": "Aya"
    }
  ]
}
